import{c as o,Q as e,j as r,m as a}from"./chunks/framework.hhGiamYR.js";const c=JSON.parse('{"title":"致刚走上领导岗位的年轻人·再及——喀戎、地狱与一封补充的信","description":"","frontmatter":{"title":"致刚走上领导岗位的年轻人·再及——喀戎、地狱与一封补充的信","date":"2026-05-29T00:00:00.000Z","source":"co-created","seed":"续上封信，深夜增补","style":"let","tags":["领导力","喀戎","实效真理","书信体","解雇"],"skill_used":"Machiavelli Digital Twin v1.8.0"},"headers":[],"relativePath":"seeds/young-leader-part2/index.md","filePath":"seeds/young-leader-part2/index.md"}'),l={name:"seeds/young-leader-part2/index.md"};function p(u,t,n,i,s,q){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="致刚走上领导岗位的年轻人·再及——喀戎、地狱与一封补充的信" tabindex="-1">致刚走上领导岗位的年轻人·再及——喀戎、地狱与一封补充的信 <a class="header-anchor" href="#致刚走上领导岗位的年轻人·再及——喀戎、地狱与一封补充的信" aria-label="Permalink to &quot;致刚走上领导岗位的年轻人·再及——喀戎、地狱与一封补充的信&quot;">​</a></h1><blockquote><p>你收到上一封信后大约过了一天。当时写得匆忙——乡下的公鸡刚打完第一声鸣，我就把信封装了。事后想来，上一封信说了不少，但没说透。坐在火炉边上重新想了想，有几条补上。</p></blockquote><h2 id="关于-狮子和狐狸-为什么不够——你需要成为喀戎" tabindex="-1">关于&quot;狮子和狐狸&quot;为什么不够——你需要成为喀戎 <a class="header-anchor" href="#关于-狮子和狐狸-为什么不够——你需要成为喀戎" aria-label="Permalink to &quot;关于&quot;狮子和狐狸&quot;为什么不够——你需要成为喀戎&quot;">​</a></h2><p>上一封信我告诉你要建立结构——要求明确、奖惩分明。这没错。但如果你只做到这些，你会变成一个让下属表面上执行、背地里诅咒的人。结构是骨架。你需要的是<strong>在骨架上的活人肌肉。</strong></p><p>古代作家们讲过一个故事——阿基琉斯被交给马人喀戎抚养。喀戎既是医者，又是武士；既温和，又凶猛。</p><blockquote><p>📖 <strong>原文</strong>：《君主论》第18章</p><p>&quot;古代作家们已经隐蔽地教授了君主们这一招数：他们描写阿基琉斯以及其他许多古代的君主被交给马人喀戎抚养，并且在他的训练下管教成人。以半人半兽为导师，这不外乎说，一位君主需要懂得如何使用两种特性〔人性和兽性〕；如果只具有一种特性而缺乏另一种特性，那么都不会持久。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>这对你意味着什么？</p><p>你太执着于&quot;人性的那一半&quot;——以理服人、温和沟通、希望下属理解和认同。但你没有使用&quot;兽性的那一半&quot;——明确的后果、不容商量的底线、在必要时展示力量。</p><p>这不是&quot;变成坏人&quot;。这是<strong>两个工具箱都打开。</strong></p><p>喀戎前半段教你治疗——倾听、理解、共情。后半段教你战斗——面对抵抗、坚持底线、不回避冲突。领导一个新团队就像培养一个马童：先教他如何照顾马匹，但如果有天马脱缰了，教他如何追上去、抓住缰绳、哪怕摔在地上也不能松手。</p><p><strong>把你的两种能力分开使用。</strong> 在日常安排工作时，用你的人性那一半——商量、解释、给空间。但在底线问题上——任务截止日、质量标准、团队纪律——把你的判断交给&quot;非人性&quot;的那一半。不是愤怒，不是自尊——是冷静的、计算的、不容模糊的裁决。</p><p>这是不是有点讽刺？是的。一个刚刚还在和你讨论罗马史的书的和善老头，现在告诉你：<strong>把一部分冰冷的规则外化，把它变成一个自动执行的机制，这样当你使用人性那一面的时候就不会被当成软弱的信号。</strong></p><h2 id="关于你的-道德困境-——一个更深的问题" tabindex="-1">关于你的&quot;道德困境&quot;——一个更深的问题 <a class="header-anchor" href="#关于你的-道德困境-——一个更深的问题" aria-label="Permalink to &quot;关于你的&quot;道德困境&quot;——一个更深的问题&quot;">​</a></h2><p>上一封信我说&quot;道德困境是因为你混淆了应然和实然&quot;。现在我想说点更深的——</p><p>你的道德困境的真正根源不是认知。是恐惧。你怕的不是&quot;做错事&quot;——你怕的是&quot;被人认为是坏人&quot;。你怕下属在背后说&quot;新来的那个领导太狠了&quot;。你怕你的上司看了你的管理方式后觉得你不近人情。</p><p>我在另一封信里写过一段话，关于天堂和地狱：</p><blockquote><p>📖 <strong>原文</strong>：致弗朗切斯科·圭恰迪尼，书信270</p><p>&quot;我相信，上天堂的真正道路，是先熟悉下地狱的道路，以避免下地狱。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/letters/1513-1527.md" target="_blank" rel="noreferrer">阅读原文</a></p></blockquote><p>这句话不是说&quot;去做恶人&quot;。它是说<strong>你不能害怕接触这个世界里存在着的那些不那么美好的东西——强硬、压力、不容商量的边界。</strong> 你必须先熟悉它们、了解它们在何时是必需的，然后你才不会滥用它们。</p><p>你害怕&quot;苛待别人&quot;——但你有没有想过，一个团队里有人不做自己的那部分工作，实际上是这个人在苛待所有其他做了的人？你容忍一个不干活的人——你的&quot;宽容&quot;不是在保护他，是在<strong>贬低那个干得最多的下属的劳动。</strong></p><p>所以你的道德困境要重新排列：第一优先不是&quot;我不要变成苛待别人的人&quot;，而是&quot;这个团队里每个人的付出是不是得到了公平的评价&quot;。如果答案是否定的——那么使用你非人性的那一半<strong>就是道德的。</strong></p><h2 id="关于给你的信的本身" tabindex="-1">关于给你的信的本身 <a class="header-anchor" href="#关于给你的信的本身" aria-label="Permalink to &quot;关于给你的信的本身&quot;">​</a></h2><p>上一封信，我花了太多时间在讲结构和规则。但现在想来——一个最本质的东西我漏掉了：<strong>这封信本身就是一场表演。</strong></p><p>我写给韦托里的那些信，不只是私人通信——它们是在塑造一个&quot;配得上写《君主论》&quot;的人格。我不是在记录我是谁，我是在建造我是谁。</p><p>同样——<strong>你现在给下属写的每一封邮件、每一次会议讲话、每一次私下谈话，都是你的自我建构。</strong> 他们在通过这些看你不是什么样的人，而是你想成为什么样的人。所以：</p><ul><li>不要发&quot;大家辛苦了&quot;的客套话——除非你真的知道谁辛苦、为什么辛苦</li><li>不要在会议上说&quot;这个问题我们再研究&quot;——除非你能说出&quot;这个问题的哪些部分还需要什么信息&quot;</li><li>不要在收到抱怨时立刻道歉——先确认&quot;你抱怨的事情是否真的发生了，以及你希望我做什么&quot;</li></ul><p>你的每一次发言，如果你自己不先想清楚你要成为谁，别人就会替你想清楚——然后那个版本通常对你不太好。</p><h2 id="最后——如果一切都不管用" tabindex="-1">最后——如果一切都不管用 <a class="header-anchor" href="#最后——如果一切都不管用" aria-label="Permalink to &quot;最后——如果一切都不管用&quot;">​</a></h2><p>如果结构建了、喀戎的两面都用了、发言也谨慎了——还是有人不配合。</p><p><strong>解雇比感化更需要勇气——通常也是更道德的决定。</strong></p><p>留着不配合的人在你的团队里，你不是在对他仁慈。你是在对团队里的其他人残忍。你花了六个月的时间去感化一个人，在那六个月里，其他五个配合的人每天都在降低自己的标准来适应那个不做事的人的存在。六个月后，你不只失去了他一个人——你让五个人退步了。</p><p>在一个不完美世界里，面对邪恶唯一能做出良善的选择的方式是：先熟悉邪恶长什么样、它如何潜伏、何时必须切除。</p><hr><p><em>尼科洛·马基雅维利 圣卡夏诺，深夜——笔迹潦草，但想得比昨天透。</em></p><hr><p><em>原文可于 <a href="https://niflhum.top/machiavelli-library/" target="_blank" rel="noreferrer">machiavelli-library</a> 查证</em></p>',35)])])}const d=o(l,[["render",p]]);export{c as __pageData,d as default};
